"""
Fix W16: remove the wrong W16 rows from each disease xlsx, re-add with corrected col_idx (shifted by -1).
"""
import json, re, sys
from pathlib import Path
import openpyxl
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from datetime import datetime

BASE_DIR = Path('/sessions/eager-laughing-sagan/mnt/claude')
DISEASES_DIR = BASE_DIR / 'diseases'
STATE_FILE = BASE_DIR / 'state.json'
LOG_FILE = BASE_DIR / 'collect_log.txt'

def log(msg):
    ts = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    line = f'[{ts}] {msg}'
    print(line)
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(line + '\n')

def safe_dirname(name):
    return re.sub(r'[\\/:*?"<>|]', '_', name)

def get_val(row_data, col_idx):
    try:
        return int(row_data[col_idx])
    except (IndexError, ValueError, TypeError):
        return 0

def _make_styles():
    thin = Side(style='thin', color='CCCCCC')
    border = Border(left=thin, right=thin, top=thin, bottom=thin)
    data_font  = Font(name='Arial', size=9)
    zero_font  = Font(name='Arial', size=9, color='AAAAAA')
    total_font = Font(name='Arial', bold=True, size=9)
    total_fill = PatternFill('solid', start_color='FFF2CC')
    right = Alignment(horizontal='right', vertical='center')
    center = Alignment(horizontal='center', vertical='center')
    return border, data_font, zero_font, total_font, total_fill, right, center

STYLES = _make_styles()

def remove_week_row(xlsx_path, year, week):
    """Remove rows where col0=year and col1=week."""
    if not xlsx_path.exists():
        return False
    try:
        wb = openpyxl.load_workbook(str(xlsx_path))
        ws = wb['速報データ']
        rows_to_delete = []
        for ri, row in enumerate(ws.iter_rows(min_row=5, max_row=ws.max_row, values_only=True), start=5):
            if row[0] == year and row[1] == week:
                rows_to_delete.append(ri)
        for ri in reversed(rows_to_delete):
            ws.delete_rows(ri, 1)
        wb.save(str(xlsx_path))
        wb.close()
        return len(rows_to_delete) > 0
    except Exception as e:
        log(f'  ERROR remove {xlsx_path.name}: {e}')
        return False

def append_week_to_excel(xlsx_path, disease, parsed):
    if not xlsx_path.exists():
        return False
    col_report = disease['col_idx']
    col_cumul  = disease['col_idx'] + 1
    FIXED_COLS = 4
    border, data_font, zero_font, total_font, total_fill, right, center = STYLES
    try:
        wb = openpyxl.load_workbook(str(xlsx_path))
        ws = wb['速報データ']
        next_row = ws.max_row + 1
        if next_row < 5: next_row = 5
        for row in ws.iter_rows(min_row=5, max_row=ws.max_row, values_only=True):
            if row[0] == parsed['year'] and row[1] == parsed['week']:
                wb.close()
                return False
        for ci, val in enumerate([parsed['year'], parsed['week'], parsed['period'], parsed['created']], start=1):
            cell = ws.cell(row=next_row, column=ci, value=val)
            cell.font = data_font; cell.alignment = center; cell.border = border
        for pi, pref in enumerate(parsed['prefectures']):
            row_data = parsed['data'].get(pref, [])
            val_rep = get_val(row_data, col_report)
            val_cum = get_val(row_data, col_cumul)
            c_rep = FIXED_COLS + pi * 2 + 1
            c_cum = FIXED_COLS + pi * 2 + 2
            for c, val in [(c_rep, val_rep), (c_cum, val_cum)]:
                cell = ws.cell(row=next_row, column=c, value=val)
                cell.font = zero_font if val == 0 else data_font
                cell.alignment = right; cell.border = border
            if pref == '総数':
                for c in [c_rep, c_cum]:
                    ws.cell(row=next_row, column=c).fill = total_fill
                    ws.cell(row=next_row, column=c).font = total_font
        if '疾病情報' in wb.sheetnames:
            wb['疾病情報']['B5'] = parsed['created']
        wb.save(str(xlsx_path))
        wb.close()
        return True
    except Exception as e:
        log(f'  ERROR append {xlsx_path.name}: {e}')
        return False

