# ============================================================
# メイン処理
# ============================================================
log('=' * 60)
log('2026年第16週 速報データ修正開始 (col_idx -1 補正版)')
log('=' * 60)

# Verify
print(f"結核 col_idx={[d['col_idx'] for d in parsed['diseases'] if d['name']=='結核'][0]}")
print(f"  総数 結核 報告 = {parsed['data']['総数'][16]} (expected 249)")
print(f"  総数 結核 累積 = {parsed['data']['総数'][17]} (expected 4131)")
print(f"麻しん col_idx={[d['col_idx'] for d in parsed['diseases'] if d['name']=='麻しん'][0]}")
print(f"  総数 麻しん 報告 = {parsed['data']['総数'][172]} (expected 57)")
print(f"  総数 麻しん 累積 = {parsed['data']['総数'][173]} (expected 362)")

removed = 0
for disease in parsed['diseases']:
    dname = disease['name']
    folder = DISEASES_DIR / safe_dirname(dname)
    xlsx = folder / f'{safe_dirname(dname)}.xlsx'
    if remove_week_row(xlsx, parsed['year'], parsed['week']):
        removed += 1
log(f'  W16既存行削除: {removed}件')

updated = 0
skipped = 0
for disease in parsed['diseases']:
    dname = disease['name']
    folder = DISEASES_DIR / safe_dirname(dname)
    xlsx = folder / f'{safe_dirname(dname)}.xlsx'
    ok = append_week_to_excel(xlsx, disease, parsed)
    if ok:
        updated += 1
    else:
        skipped += 1

log(f'  Excel更新: {updated}件成功 / {skipped}件スキップ')

with open(STATE_FILE, encoding='utf-8') as f:
    state = json.load(f)

if '2026-W16' not in state['processed_weeks']:
    state['processed_weeks'].append('2026-W16')
state['last_run'] = datetime.now().isoformat()
state['2026-W16_updated'] = updated

with open(STATE_FILE, 'w', encoding='utf-8') as f:
    json.dump(state, f, ensure_ascii=False, indent=2)

log(f'  状態ファイル更新: 2026-W16 修正完了')
log('=' * 60)
